typedef struct { long long m, b; } Line;

static void convex_hull_trick_impl(int n, long long* ms, long long* bs,
                                   int q, long long* queries, long long* results) {
    for (int i = 0; i < q; i++) {
        long long x = queries[i];
        long long best = 0;
        for (int j = 0; j < n; j++) {
            long long value = (ms[j] * x) + bs[j];
            if (j == 0 || value < best) {
                best = value;
            }
        }
        results[i] = best;
    }
}

