int* convex_hull_trick(int arr[], int size, int* out_size) {
    if (size < 1) {
        *out_size = 0;
        return NULL;
    }

    int n = arr[0];
    if (n < 0 || size < 1 + (2 * n)) {
        *out_size = 0;
        return NULL;
    }

    int q = size - 1 - (2 * n);
    if (q < 0) {
        *out_size = 0;
        return NULL;
    }

    long long* ms = (long long*)malloc((n > 0 ? n : 1) * sizeof(long long));
    long long* bs = (long long*)malloc((n > 0 ? n : 1) * sizeof(long long));
    long long* queries = (long long*)malloc((q > 0 ? q : 1) * sizeof(long long));
    long long* tmp = (long long*)malloc((q > 0 ? q : 1) * sizeof(long long));
    int* result = (int*)malloc((q > 0 ? q : 1) * sizeof(int));
    if (!ms || !bs || !queries || !tmp || !result) {
        free(ms); free(bs); free(queries); free(tmp); free(result);
        *out_size = 0;
        return NULL;
    }

    for (int i = 0; i < n; i++) {
        ms[i] = arr[1 + (2 * i)];
        bs[i] = arr[1 + (2 * i) + 1];
    }
    for (int i = 0; i < q; i++) {
        queries[i] = arr[1 + (2 * n) + i];
    }

    convex_hull_trick_impl(n, ms, bs, q, queries, tmp);
    for (int i = 0; i < q; i++) {
        result[i] = (int)tmp[i];
    }

    free(ms);
    free(bs);
    free(queries);
    free(tmp);
    *out_size = q;
    return result;
}

#include <limits>
#include <vector>

std::vector<long long> convex_hull_trick(
    int n,
    const std::vector<std::vector<int>>& lines,
    const std::vector<int>& queries
) {
    std::vector<long long> result;
    result.reserve(queries.size());

    for (int x : queries) {
        long long best = std::numeric_limits<long long>::max();
        for (int index = 0; index < n && index < static_cast<int>(lines.size()); ++index) {
            if (lines[index].size() < 2) {
                continue;
            }
            long long m = lines[index][0];
            long long b = lines[index][1];
            long long value = m * static_cast<long long>(x) + b;
            if (value < best) {
                best = value;
            }
        }
        result.push_back(best == std::numeric_limits<long long>::max() ? 0 : best);
    }

    return result;
}

using System;
